quand je lance ce programme :from itertools import permutations

# Création du graphe
def creer_graphe():
    G = {}
    sommets = input("Veuillez entrer les noms des sommets (maximum 5), séparés par des espaces: ").split()
    arretes = input("Veuillez entrer les arêtes comme 'A B', séparées par des espaces. Inclure les boucles comme 'AA': ").split()
    for sommet in sommets:
        G[sommet] = []
    for arete in arretes:
        depart, arrivee = arete[0], arete[1] if len(arete) > 1 else arete[0]
        G[depart].append(arrivee)
    return G, sommets

# Vérification si un chemin est hamiltonien
def est_hamiltonien(chemin, sommets):
    return len(set(chemin)) == len(sommets)

# Recherche de chemins/circuits
def chercher_chemins(G, sommets, longueur, depart, arrivee):
    results = []
    for chemin in permutations(sommets, longueur):
        if chemin[0] == depart and (arrivee is None or chemin[-1] == arrivee):
            if all(chemin[i] in G[chemin[i-1]] for i in range(1, len(chemin))):
                results.append(chemin)
    return results

# Programme principal
G, sommets = creer_graphe()
while True:
    longueur = int(input("Quelle est la longueur du chemin? "))
    depart = input("Quel est le point de départ? ")
    arrivee = input("Quel est le point d'arrivée? (tapez 'None' si ce n'est pas un circuit)")

    results = chercher_chemins(G, sommets, longueur, depart, arrivee)
    for result in results:
        if est_hamiltonien(result, sommets):
            print(' -> '.join(result), "(Ceci est un chemin Hamiltonien)")
        else:
            print(' -> '.join(result))

    if input("Voulez-vous faire une autre recherche? (oui/non): ") != 'oui':
        break
